168→/// User-provided mock override from `.shatter/config.yaml`.
169→#[derive(Debug, Clone, PartialEq, serde::Deserialize, serde::Serialize)]
170→pub struct MockOverride {
171→    /// Pre-configured return values, replacing auto-generated defaults.
172→    #[serde(default)]
173→    pub return_values: Option<Vec<Value>>,
174→    /// Override the default behavior.
175→    #[serde(default)]
176→    pub behavior: Option<MockBehavior>,
177→}
178→
179→/// Generate auto-mocks for all dependencies of a function.
180→///
181→/// Returns mock configs for dependencies that:
182→/// 1. Are not already covered by `existing_mocks` (e.g., behavior-map mocks)
183→/// 2. Are classified as Mock (not Passthrough or Analyze) by the scope matcher
184→///
185→/// User overrides from config take precedence over auto-generated defaults.
186→pub fn generate_auto_mocks(
187→    deps: &[ExternalDependency],
188→    scope: Option<&ScopeMatcher>,
189→    overrides: &HashMap<String, MockOverride>,
190→    existing_mocks: &[MockConfig],
191→) -> Vec<MockConfig> {
192→    let already_mocked: std::collections::HashSet<&str> = existing_mocks
193→        .iter()
194→        .map(|m| m.symbol.as_str())
195→        .collect();
196→
197→    let mut result = Vec::new();
198→
199→    for dep in deps {
200→        // Skip if already covered by a behavior-map mock
201→        if already_mocked.contains(dep.symbol.as_str()) {
202→            continue;
203→        }
204→
205→        // Check scope: if Passthrough, skip; if Analyze (no rule), use category logic
206→        if let Some(matcher) = scope {
207→            match matcher.classify_dependency(&dep.symbol) {
208→                DependencyAction::Passthrough => continue,
209→                DependencyAction::Mock | DependencyAction::Analyze => {}
210→            }
211→        }
212→
213→        let category = classify_dependency(dep);
214→
215→        // Pure utilities default to passthrough — skip generating a mock
216→        if category == IoCategory::PureUtility && !overrides.contains_key(&dep.symbol) {
217→            continue;
218→        }
219→
220→        let mut mock = generate_default_mock(dep, category);
221→
222→        // Apply user overrides
223→        if let Some(ov) = overrides.get(&dep.symbol) {
224→            if let Some(ref vals) = ov.return_values {
225→                mock.return_values = vals.clone();
226→            }
227→            if let Some(ref behavior) = ov.behavior {
228→                mock.default_behavior = behavior.clone();
229→            }
230→        }
231→
232→        result.push(mock);
233→    }
234→
235→    result
236→}
