222→/**
223→ * Run garbage collection if --expose-gc is enabled.
224→ * This gives more accurate heap measurements by clearing unreachable objects.
225→ */
226→function tryGc(): void {
227→  if (typeof globalThis.gc === "function") {
228→    globalThis.gc();
229→  }
230→}
