406→/**
407→ * Create an intercepting console that records all output as side effects.
408→ *
409→ * Captures: log, warn, error, info, debug (level mapped 1:1),
410→ * dir/table/dirxml (→ "log"), trace (→ "debug"), count/countReset (→ "log"),
411→ * time/timeEnd/timeLog (→ "log"). Non-output methods (group, clear, assert,
412→ * profile, timeStamp) delegate to the real console.
413→ */
414→function createCapturingConsole(sideEffects: SideEffect[]): Console {
415→  const makeLogger = (level: string) => (...args: unknown[]): void => {
416→    const message = truncateMessage(args.map((a) =>
417→      typeof a === "string" ? a : JSON.stringify(a) ?? String(a)
418→    ).join(" "));
419→    sideEffects.push({ kind: "console_output", level, message });
420→  };
421→
422→  const logFn = makeLogger("log");
423→  const debugFn = makeLogger("debug");
424→
425→  // Counters for console.count / console.countReset
426→  const counters = new Map<string, number>();
427→
428→  // Timers for console.time / console.timeEnd / console.timeLog
429→  const timers = new Map<string, number>();
430→
431→  return {
432→    log: logFn,
433→    warn: makeLogger("warn"),
434→    error: makeLogger("error"),
435→    info: makeLogger("info"),
436→    debug: debugFn,
437→    dir: (...args: unknown[]) => logFn(...args),
438→    table: (...args: unknown[]) => logFn(...args),
439→    dirxml: (...args: unknown[]) => logFn(...args),
440→    trace: (...args: unknown[]) => {
441→      debugFn("Trace:", ...args);
442→    },
443→    count: (label = "default") => {
444→      const n = (counters.get(label) ?? 0) + 1;
445→      counters.set(label, n);
446→      logFn(`${label}: ${n}`);
447→    },
448→    countReset: (label = "default") => {
449→      counters.set(label, 0);
450→    },
451→    time: (label = "default") => {
452→      timers.set(label, performance.now());
453→    },
454→    timeEnd: (label = "default") => {
455→      const start = timers.get(label);
456→      if (start !== undefined) {
457→        logFn(`${label}: ${(performance.now() - start).toFixed(3)}ms`);
458→        timers.delete(label);
459→      }
460→    },
461→    timeLog: (label = "default", ...args: unknown[]) => {
462→      const start = timers.get(label);
463→      if (start !== undefined) {
464→        logFn(`${label}: ${(performance.now() - start).toFixed(3)}ms`, ...args);
465→      }
466→    },
467→    assert: console.assert,
468→    clear: console.clear,
469→    group: console.group,
470→    groupCollapsed: console.groupCollapsed,
471→    groupEnd: console.groupEnd,
472→    profile: console.profile,
473→    profileEnd: console.profileEnd,
474→    timeStamp: console.timeStamp,
475→    Console: console.Console,
476→  } as unknown as Console;
477→}
