 72→/**
 73→ * Analyze functions in a TypeScript file.
 74→ *
 75→ * If `functionName` is provided, only that function is returned.
 76→ * Otherwise, all top-level exported functions are returned.
 77→ */
 78→export function analyzeFile(filePath: string, functionName?: string | null, projectRoot?: string | null): FunctionAnalysis[] {
 79→  const absolutePath = path.resolve(filePath);
 80→  const compilerOptions = loadCompilerOptions(absolutePath, projectRoot ?? undefined);
 81→  const program = ts.createProgram([absolutePath], compilerOptions);
