165→function analyzeFunctionDeclaration(
166→  node: ts.FunctionDeclaration,
167→  checker: ts.TypeChecker,
168→  sourceFile: ts.SourceFile,
169→  exported: boolean,
170→): FunctionAnalysis | null {
171→  if (!node.name) return null;
172→
173→  const name = node.name.text;
174→  const params = node.parameters.map((p) => analyzeParameter(p, checker));
175→  const paramNames = new Set(params.map((p) => p.name));
176→
177→  const sig = checker.getSignatureFromDeclaration(node);
178→  const returnType = sig
179→    ? convertType(checker.getReturnTypeOfSignature(sig), checker)
180→    : { kind: "unknown" as const };
181→
182→  const startLine = sourceFile.getLineAndCharacterOfPosition(node.getStart(sourceFile)).line + 1;
183→  const endLine = sourceFile.getLineAndCharacterOfPosition(node.getEnd()).line + 1;
184→
185→  const branches = node.body ? extractBranches(node.body, sourceFile, paramNames) : [];
186→  const dependencies = node.body ? extractDependencies(node.body, checker, sourceFile, paramNames) : [];
187→  const literals = extractLiterals(node, sourceFile, checker);
188→
189→  return {
190→    name,
191→    exported,
192→    params,
193→    branches,
194→    dependencies,
195→    return_type: returnType,
196→    start_line: startLine,
197→    end_line: endLine,
198→    ...(literals.length > 0 ? { literals } : {}),
199→  };
200→}

