638→/**
639→ * Walk a function body and detect calls to external (imported/other-file) functions.
640→ */
641→function extractDependencies(
642→  body: ts.Block,
643→  checker: ts.TypeChecker,
644→  sourceFile: ts.SourceFile,
645→  paramNames: Set<string>,
646→): ExternalDependency[] {
647→  const accumulators = new Map<string, DependencyAccumulator>();
648→
649→  walkForDependencies(body, checker, sourceFile, paramNames, accumulators);
650→
651→  return Array.from(accumulators.values()).map((acc) => ({
652→    kind: acc.kind,
653→    symbol: acc.symbol,
654→    source_module: acc.sourceModule,
655→    return_type: acc.returnType,
656→    param_types: acc.paramTypes,
657→    call_sites: acc.callSites,
658→  }));
659→}
660→
661→function walkForDependencies(
662→  node: ts.Node,
663→  checker: ts.TypeChecker,
664→  sourceFile: ts.SourceFile,
665→  paramNames: Set<string>,
666→  accumulators: Map<string, DependencyAccumulator>,
667→): void {
668→  if (ts.isCallExpression(node)) {
669→    const callee = node.expression;
670→    const line = sourceFile.getLineAndCharacterOfPosition(node.getStart(sourceFile)).line + 1;
671→
672→    let symbol: ts.Symbol | undefined;
673→    let depKind: DependencyKind = "function_call";
674→    let symbolName: string | undefined;
675→
676→    if (ts.isIdentifier(callee)) {
677→      symbol = checker.getSymbolAtLocation(callee);
678→      symbolName = callee.text;
679→    } else if (ts.isPropertyAccessExpression(callee)) {
680→      symbol = checker.getSymbolAtLocation(callee.name);
681→      symbolName = callee.getText(sourceFile);
682→      depKind = "method_call";
683→    }
684→
685→    if (symbol && symbolName) {
686→      const resolvedSymbol = resolveAliasedSymbol(symbol, checker);
687→      const declSourceFile = getDeclarationSourceFile(resolvedSymbol);
688→
689→      if (declSourceFile && declSourceFile !== sourceFile.fileName) {
690→        const sourceModule = formatSourceModule(declSourceFile, sourceFile.fileName);
691→        const key = `${symbolName}::${sourceModule}`;
692→
693→        const existing = accumulators.get(key);
694→        if (existing) {
695→          existing.callSites.push(line);
696→        } else {
697→          const sig = checker.getResolvedSignature(node);
698→          const returnType = sig
699→            ? convertType(checker.getReturnTypeOfSignature(sig), checker)
700→            : { kind: "unknown" as const };
701→          const paramTypesArr: TypeInfo[] = sig
702→            ? sig.getParameters().map((p) => convertType(checker.getTypeOfSymbolAtLocation(p, node), checker))
703→            : [];
704→
705→          accumulators.set(key, {
706→            kind: depKind,
707→            symbol: symbolName,
708→            sourceModule,
709→            returnType,
710→            paramTypes: paramTypesArr,
711→            callSites: [line],
712→          });
713→        }
714→      }
715→    }
716→  }
717→
718→  ts.forEachChild(node, (child) =>
719→    walkForDependencies(child, checker, sourceFile, paramNames, accumulators),
720→  );
721→}
