744→/**
745→ * Format a source module path relative to the current file, producing a
746→ * human-readable module specifier.
747→ */
748→function formatSourceModule(declFile: string, currentFile: string): string {
749→  // For node_modules, extract the package name
750→  const nodeModulesIdx = declFile.lastIndexOf("node_modules/");
751→  if (nodeModulesIdx !== -1) {
752→    const afterNodeModules = declFile.substring(nodeModulesIdx + "node_modules/".length);
753→    // Handle scoped packages (@scope/name)
754→    if (afterNodeModules.startsWith("@")) {
755→      const parts = afterNodeModules.split("/");
756→      if (parts.length >= 2) {
757→        return `${parts[0]}/${parts[1]}`;
758→      }
759→    }
760→    const firstSlash = afterNodeModules.indexOf("/");
761→    return firstSlash === -1 ? afterNodeModules : afterNodeModules.substring(0, firstSlash);
762→  }
763→
764→  // For project files, compute relative path
765→  const rel = path.relative(path.dirname(currentFile), declFile);
766→  const withoutExt = rel.replace(/\.(ts|tsx|js|jsx|d\.ts)$/, "");
767→  return withoutExt.startsWith(".") ? withoutExt : `./${withoutExt}`;
768→}
